class Solution:
    def findPeaks(self, mountain):
        n = len(mountain)
        result = []
        for i in range(n):
            if i == 0 or i == n - 1:
                continue
            left_ok = mountain[i] > mountain[i - 1]
            right_ok = mountain[i] > mountain[i + 1]
            if left_ok and right_ok:
                result.append(i)
        return result

solutions.python:
class Solution:
    def findPeaks(self, mountain):
        peaks = []
        for i in range(1, len(mountain) - 1):
            if mountain[i] > mountain[i - 1] and mountain[i] > mountain[i + 1]:
                peaks.append(i)
        return peaks

